def process_payment(user, cart_items, payment_details):
    discount_percentages = {
        'basic': 0,
        'premium': 15,
        'enterprise': 30
    }

    if user.role not in discount_percentages:
        raise ValueError('Invalid user role')

    discount_percentage = discount_percentages[user.role]
    total_discount = (discount_percentage / 100) * sum(item['price'] for item in cart_items)
    total_amount = sum(item['price'] for item in cart_items) - total_discount

    if payment_details['amount'] < total_amount:
        raise ValueError('Insufficient funds')

    # Simulate payment processing
    print(f'Payment processed successfully for ${total_amount:.2f}')

# Example usage:
